INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('40d2816fc8e8213e', 'AL', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Alabama?', '["Are Alabama primaries open or closed?","Do I have to register with a party to vote in the AL primary?","How do voters choose a ballot in the Alabama primary?"]', 'Alabama utilizes an open primary system. Voters are not required to register with a political party in advance. On Election Day, any registered voter may request either the Republican or Democratic primary ballot. However, if a primary runoff occurs, a voter may only participate in the runoff of the same party they selected in the initial primary.', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State - Election Information', '2026-04-21', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('447f433738deb4f7', 'AL', '["federal","state","county"]', 'runoff_rules', 'When are primary runoffs held in Alabama?', '["Alabama primary runoff date 2026","What is the threshold to avoid a runoff in AL?","50 percent plus one rule Alabama primary"]', 'In Alabama primary elections, a candidate must receive a strict majority (50% plus one vote) to secure the nomination. If no candidate reaches this threshold, the top two vote-getters advance to a primary runoff election. For the 2026 cycle, the primary runoff is scheduled for June 16, 2026.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('b05549163caacf8d', 'AL', '["federal","state","county"]', 'runoff_rules', 'Does Alabama have runoff elections for the general election?', '["Alabama general election runoff rules","Do state candidates face a general runoff in AL?","General election majority requirement Alabama"]', 'No. Unlike the primary elections, general elections for state and federal offices in Alabama do not require a majority to win. The candidate who receives a simple plurality of the votes in the general election is declared the winner, and no general election runoff is held.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('e9aca404e5f5d30a', 'AL', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Alabama?', '["Do write-in votes count in AL?","How to register as a write-in candidate in Alabama","Write-in filing deadline Alabama"]', 'Yes, and Alabama''s system is highly distinctive: the state permits write-in votes in general elections without requiring the write-in candidate to file any pre-election paperwork or declaration of intent. Write-in votes cast on the ballot are valid and tabulated, although they are not permitted in primary elections.', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('a325492fd0ab03f5', 'AL', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for major party candidates in Alabama for 2026?', '["When do candidates file for office in Alabama?","Alabama filing deadline 2026","January filing deadline AL"]', 'Major party candidates seeking to appear on the 2026 primary ballot must file their declaration of candidacy with the state or county party chair by the statutory deadline, which is 116 days before the primary. For 2026, the filing deadline is January 23, 2026.', 'https://ballotpedia.org/Alabama_gubernatorial_election,_2026', 'Ballotpedia / Alabama Election Calendar', '2026-04-21', 'per_cycle', 'secondary_source', 'Major party candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('625d7d4be8059dcb', 'AL', '["federal","state"]', 'ballot_access', 'What is the petition threshold and deadline for independent candidates in Alabama?', '["Independent candidate petition deadline Alabama","Running without a party in AL 2026","Independent signature requirements Alabama"]', 'Independent candidates must submit a petition containing signatures of registered voters equal to at least 3% of the total votes cast for Governor in the respective district/state in the last general election. The petition must be filed by 5:00 p.m. on the date of the primary election (May 19, 2026).', 'https://www.sos.alabama.gov/alabama-votes/candidates/independent-candidates', 'Alabama Secretary of State - Independent Candidates', '2026-04-21', 'per_cycle', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('eea44621f0745149', 'AL', '["federal","state","county"]', 'ballot_access', 'Does Alabama have a sore loser law?', '["Can I run as an independent if I lose the AL primary?","Alabama sore loser statute","General election ballot access after primary defeat AL"]', 'Yes. Alabama enforces a sore loser law. A candidate who participates in a political party''s primary election and is defeated cannot subsequently qualify to have their name placed on the general election ballot as an independent candidate or the nominee of another party for the same election cycle.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Major party candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('c55d2bdb22c7bfc2', 'AL', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Alabama?', '["Alabama joint ticket rules","How are Lt Gov candidates selected in AL?","Does the Governor pick a running mate in Alabama?"]', 'No. In Alabama, the Governor and Lieutenant Governor are elected separately. They run in distinct primary and general elections and appear as separate items on the ballot, meaning voters can elect a Governor and Lieutenant Governor from two different political parties.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('7280fe1b3132378a', 'AL', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Alabama for 2026?', '["Alabama primary date 2026","When is Election Day 2026 in Alabama?","May primary Alabama"]', 'The Alabama primary election will be held on Tuesday, May 19, 2026 (with a runoff, if needed, on June 16, 2026). The general election will be held on Tuesday, November 3, 2026. Polls are open from 7:00 a.m. to 7:00 p.m.', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State - Election Dates', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('d30e72f76ecc6e70', 'AL', '["state"]', 'election_dates', 'Is Governor Kay Ivey running for re-election in 2026?', '["Alabama Governor election 2026","Who is defending the AL Governor seat?","Is Kay Ivey term limited?"]', 'No. Governor Kay Ivey (R) is term-limited and cannot seek re-election. The 2026 Alabama gubernatorial election is an open-seat race. U.S. Senator Tommy Tuberville (R) is vacating his federal seat to run for the office.', 'https://ballotpedia.org/Alabama_gubernatorial_election,_2026', 'Ballotpedia - Alabama Gubernatorial Election 2026', '2026-04-21', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('eef8eb905e4d85ae', 'AL', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Alabama in 2026?', '["Is Tommy Tuberville up for re-election in 2026?","When is Katie Britt''s next election?","Alabama US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat is up for election in 2026. Incumbent Tommy Tuberville (R) is vacating the seat to run for Governor, making it an open-seat race. Senator Katie Britt (Class 3) was elected in 2022 and will not appear on the ballot again until 2028.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('e37430fc130d10cd', 'AL', '["federal"]', 'election_dates', 'How many U.S. House districts are in Alabama for the 2026 election?', '["Alabama congressional apportionment","Are all AL congressional seats up in 2026?","Number of US Representatives from Alabama"]', 'Alabama is apportioned 7 U.S. House districts. All seven seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('2b8dbb9bfe5c39bb', 'AL', '["state"]', 'election_dates', 'Which Alabama State Legislature seats are up for election in 2026?', '["Are all Alabama House seats up in 2026?","Alabama Senate election cycle 2026","Which legislative districts are on the ballot in AL?"]', 'In Alabama, ALL legislative seats are up for election concurrently every four years, aligning with the gubernatorial cycle. Therefore, all 105 seats in the Alabama House of Representatives and all 35 seats in the Alabama State Senate will be on the 2026 ballot.', 'https://legislature.state.al.us/', 'Alabama State Legislature', '2026-04-21', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('4261ea1e135cfe28', 'AL', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Alabama in 2026?', '["Is the Attorney General up in 2026?","AL statewide election list 2026","When is the Secretary of State election in AL?"]', 'Alabama elects all of its statewide executive officers concurrently every four years during the midterm cycle. In 2026, the offices of Governor, Lieutenant Governor, Attorney General, Secretary of State, State Treasurer, State Auditor, and Commissioner of Agriculture and Industries are all on the ballot.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('3c1c9989daf41e2a', 'AL', '["judicial"]', 'election_dates', 'How are Alabama Supreme Court justices elected?', '["Alabama judicial elections 2026","Are AL judges elected or appointed?","Partisan judicial elections Alabama"]', 'Alabama Supreme Court justices are elected in statewide, partisan elections. They serve six-year terms, meaning seats are staggered across election cycles. Judicial candidates run in the standard May primary and November general elections alongside other partisan candidates.', 'https://judicial.alabama.gov/', 'Alabama Judicial System', '2026-04-21', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('631bb48d2540684a', 'AL', '["state"]', 'election_dates', 'What is the schedule for the Alabama State Legislature''s sessions?', '["When does the AL legislature meet?","Alabama legislative session length","Is the Alabama legislature full time?"]', 'The Alabama Legislature is a part-time body that meets annually. Regular sessions are limited to 30 legislative days within a 105-calendar-day period. The session generally convenes on the first Tuesday in February, except in the first year of a new quadrennium (e.g., 2027 following the 2026 election), when it convenes in early March.', 'https://legislature.state.al.us/', 'Alabama State Legislature', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('2b7de89ce4298768', 'AL', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Alabama?', '["Age and residency for Alabama Governor","Alabama Constitution Article V Governor qualifications","Who is eligible to be Governor of AL?"]', 'Under Article V, Section 117 of the Alabama Constitution, a candidate for Governor must be at least 30 years old, a citizen of the United States for at least 10 years, and a resident of Alabama for at least 7 years immediately preceding the election.', 'https://www.sos.alabama.gov/alabama-votes/candidates/qualifications-public-office', 'Alabama Secretary of State - Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('4c6512de10d8c257', 'AL', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Alabama State Legislature?', '["Qualifications for AL State Representative","Age requirement Alabama State Senate","Do I have to live in my district to run in AL?"]', 'Under Article IV, Section 47 of the Alabama Constitution, a candidate for the State Senate must be at least 25 years old, and a candidate for the State House must be at least 21 years old. Both must be Alabama residents for at least 3 years and residents of their specific district for at least 1 year prior to the election.', 'https://www.sos.alabama.gov/alabama-votes/candidates/qualifications-public-office', 'Alabama Secretary of State - Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('832088afe3da9774', 'AL', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Alabama?', '["US Senate residency requirements Alabama","Age to run for Congress in Alabama","Federal constitutional requirements for AL candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://www.sos.alabama.gov/alabama-votes/candidates/qualifications-public-office', 'Alabama Secretary of State - Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('88603424b2b7f1c1', 'AL', '["state"]', 'candidate_eligibility', 'What are the term limits for Alabama state officials?', '["How many terms can an Alabama Governor serve?","Are there term limits for the Alabama legislature?","Alabama executive term limit law"]', 'In Alabama, statewide executive officers (including the Governor, Lt. Governor, Attorney General, and Secretary of State) are limited to two consecutive four-year terms. However, there are NO term limits for members of the Alabama State Legislature (House or Senate).', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('3fbe8373622082ec', 'AL', '["state"]', 'candidate_eligibility', 'Does the Alabama Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in AL","Do I need to be a member of the bar to be AL AG?","Legal requirements for Alabama Attorney General"]', 'Yes. Beyond the standard residency and age requirements, statutory law mandates that the Attorney General of Alabama must be learned in the law and must have been admitted to practice law in the state of Alabama.', 'https://www.sos.alabama.gov/alabama-votes/candidates/qualifications-public-office', 'Alabama Secretary of State - Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('7c9da249b47609ae', 'AL', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Alabama?', '["Alabama Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in AL?","Qualifications for Lieutenant Governor of Alabama"]', 'Under Article V of the Alabama Constitution, the qualifications for Lieutenant Governor are strictly identical to those for Governor: a candidate must be at least 30 years old, a U.S. citizen for 10 years, and an Alabama resident for 7 years.', 'https://www.sos.alabama.gov/alabama-votes/candidates/qualifications-public-office', 'Alabama Secretary of State - Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('a0fb797d467be670', 'AL', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Alabama?', '["Alabama county commissioner qualifications","Can I run for county board in AL?","County residency for AL officials"]', 'To run for a county office (such as County Commissioner, Sheriff, or Probate Judge), a candidate must generally be a qualified elector (registered voter) of the county and must have resided in the county (or specific district) for at least one year immediately prior to the election.', 'https://www.sos.alabama.gov/alabama-votes/candidates/qualifications-public-office', 'Alabama Secretary of State - Local Candidate Qualifications', '2026-04-21', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('ed067c4718323b51', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Alabama?', '["Alabama voter ID requirements","Do I need my driver''s license to vote in AL?","Acceptable ID for Alabama voting"]', 'Yes. Alabama has a strict photo ID requirement. Voters must present a valid photo ID at the polls. Acceptable forms include an Alabama driver''s license, U.S. passport, military ID, or a free Alabama Photo Voter ID card issued by the Secretary of State.', 'https://www.sos.alabama.gov/alabama-votes/photo-voter-id/valid-ids', 'Alabama Secretary of State - Voter ID', '2026-04-21', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('e20ebcfa0ec7f45d', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Alabama a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Alabama?","Alabama vote-by-mail system","Do I need an excuse to vote absentee in AL?"]', 'No. Alabama is NOT a universal mail ballot state and strictly prohibits no-excuse absentee voting. Voters must provide a legally valid excuse to request an absentee ballot, such as illness, physical disability, being out of the county on Election Day, or working a shift of 10 or more hours that coincides with polling hours.', 'https://www.sos.alabama.gov/alabama-votes/voter/absentee-voting', 'Alabama Secretary of State - Absentee Voting', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('49bc046ce7b1e6d6', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in Alabama?', '["When is the last day to mail my ballot in AL?","Alabama mail ballot postmark deadline","What time are ballots due in Alabama?"]', 'Alabama has strict absentee deadlines. If returned by mail, the ballot must be RECEIVED by the Absentee Election Manager no later than Noon on Election Day (postmarks do not extend the deadline). If hand-delivered by the voter, it must be received by the close of business (5:00 p.m.) on the day prior to the election.', 'https://www.sos.alabama.gov/alabama-votes/voter/absentee-voting', 'Alabama Secretary of State - Absentee Voting', '2026-04-21', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('c32edd3f23a08bfb', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Alabama offer same-day registration?', '["Last day to register to vote in AL","Alabama same day voter registration","Voter registration deadline 2026 Alabama"]', 'The deadline to register to vote in Alabama is 15 days before the election. Registration can be completed online, by mail, or in person. Alabama DOES NOT offer same-day voter registration at the polls.', 'https://www.sos.alabama.gov/alabama-votes/voter/register-to-vote', 'Alabama Secretary of State - Voter Registration', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('75825a70014894e3', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Alabama?', '["How close can I campaign to a polling place in AL?","Alabama 30 feet electioneering rule","AL buffer zone around voting centers"]', 'Under Alabama Code § 17-9-50, electioneering is strictly prohibited within 30 feet of the door of the building in which the polling place is located. Loitering, handing out campaign materials, or soliciting votes inside this zone is illegal on Election Day.', 'https://codes.findlaw.com/al/title-17-elections/al-code-sect-17-9-50/', 'Alabama Code § 17-9-50', '2026-04-21', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('926292c3759455b6', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Alabama?', '["Can felons vote in Alabama state?","Felony voting rights restoration AL","Voting on parole in Alabama"]', 'In Alabama, an individual loses their voting rights if convicted of a felony involving ''moral turpitude'' (e.g., murder, kidnapping, treason). To restore voting rights, the individual must complete their sentence, pay all fines and restitution, and apply to the Board of Pardons and Paroles for a Certificate of Eligibility to Register to Vote (CERV).', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State', '2026-04-21', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('162963bc7d7a87f5', 'AL', '["county"]', 'voter_interaction', 'How many counties are in Alabama, and why does it matter for campaigns?', '["Alabama county election administration","How many probate judges in AL?","Local election control Alabama"]', 'Alabama has 67 counties. Election administration is handled at the county level by a combination of Probate Judges, Circuit Clerks, and Absentee Election Managers, requiring statewide campaigns to coordinate logistics across 67 separate administrative jurisdictions.', 'https://www.sos.alabama.gov/alabama-votes/board-of-registrars-all-counties', 'Alabama Secretary of State - Local Administrators', '2026-04-21', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('884ec35795682e87', 'AL', '["state","county"]', 'finance_ethics', 'What are the campaign contribution limits in Alabama for the 2026 cycle?', '["Are there contribution limits in Alabama?","AL individual donation caps 2026 election","How much can I donate to a candidate in Alabama?"]', 'Alabama has NO contribution limits for candidates running for state or local office. Individuals, PACs, and political parties may contribute completely unlimited amounts of money to campaigns. The legislature eliminated the previous $500 cap on corporate contributions with the passage of SB 445 in 2013.', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission / FCPA', '2026-04-21', 'static', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('d5f1543281820d2a', 'AL', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Alabama campaigns?', '["Corporate contribution ban Alabama state","Can a business donate to my campaign in AL?","Corporate campaign finance rules Alabama"]', 'Yes. Direct corporate and labor union contributions to candidate campaigns are completely permitted in Alabama. Following the passage of SB 445 in 2013, these contributions can be made in unlimited amounts, making Alabama one of the most permissive states for corporate campaign finance.', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission / Fair Campaign Practices Act', '2026-04-21', 'static', 'secondary_source', 'Candidates and Businesses', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('11a11a6d1b3f6288', 'AL', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Alabama?', '["Where do I file campaign finance reports in AL?","What is the Alabama Ethics Commission?","Does the AL Secretary of State handle campaign finance?"]', 'Campaign finance reporting and enforcement is jointly administered by the Alabama Secretary of State (who manages the electronic FCPA reporting system) and the Alabama Ethics Commission (which interprets and enforces the Fair Campaign Practices Act).', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA Reporting', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('af5e4b591e452d75', 'AL', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Alabama candidates?', '["AL filing dates 2026","When are campaign finance reports due in AL?","Alabama FCPA reporting deadlines"]', 'In an election year, the reporting schedule intensifies. Candidates file monthly reports initially. Beginning four weeks before an election, they transition to filing weekly reports. For 2026 candidates, daily reporting may be triggered immediately prior to the election for large contributions.', 'https://fcpa.alabamavotes.gov/PublicSite/Resources/ElectionCycle2026.pdf', 'Alabama Secretary of State - FCPA Calendar', '2026-04-21', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('4f3881bb5f37cf2f', 'AL', '["state","county","municipal"]', 'finance_ethics', 'What are Alabama''s rapid disclosure requirements for large contributions?', '["Alabama daily large contribution report","Late contribution reporting Alabama FCPA","When do I file a rapid report in AL?"]', 'Under the FCPA, a ''major contribution'' report must be filed within two (2) business days if a candidate receives a single contribution of $20,000 or more at any time. Furthermore, if a candidate receives $5,000 or more in a single day during the eight (8) days prior to the election, it triggers daily reporting.', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA Guide', '2026-04-21', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('77a19cb8da502525', 'AL', '["state"]', 'finance_ethics', 'Does Alabama provide public financing for state campaigns?', '["Public matching funds for Alabama Governor","State funded campaigns Alabama status","Government campaign grants AL"]', 'No. Alabama does not have a system of public financing or matching funds for political campaigns. All candidates must fund their campaigns entirely through private contributions.', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission', '2026-04-21', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('f8ad5301d904693b', 'AL', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Alabama?', '["AL personal use prohibition campaign finance","Can I use campaign money for personal items in AL?","Prohibited expenditures Alabama Ethics Commission"]', 'Yes. Under the Alabama Fair Campaign Practices Act (FCPA), campaign funds cannot be converted to personal use. Expenditures must be reasonably related to an election campaign or to the ordinary and necessary expenses of holding public office.', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission', '2026-04-21', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('98a84e72255753f5', 'AL', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Alabama legislators?', '["Can Alabama legislators raise money during session?","Lobbyist contribution ban AL legislature","Legislative session contribution rules Alabama"]', 'Yes. Under Alabama Code § 17-5-7(b)(2), state lawmakers, statewide elected officials, and candidates for those offices are strictly prohibited from soliciting or accepting campaign contributions while the legislature is convened in a regular legislative session. The freeze applies for the duration of the session.', 'https://codes.findlaw.com/al/title-17-elections/al-code-sect-17-5-7/', 'Alabama Code § 17-5-7', '2026-04-21', 'static', 'statute_citation', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('f483e648eb741c91', 'AL', '["federal","state"]', 'redistricting', 'Who draws Alabama''s congressional and state legislative maps?', '["Does the AL legislature draw district maps?","Who has the authority to draw district lines in Alabama?","Alabama redistricting commission"]', 'In Alabama, the state legislature holds the exclusive authority to draw and enact both congressional and state legislative district boundaries. The maps are passed as regular legislation and are subject to the Governor''s signature or veto.', 'https://ballotpedia.org/Redistricting_in_Alabama', 'Ballotpedia - Redistricting in Alabama', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('63d33e0f83f53ed7', 'AL', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Alabama?', '["Standards for drawing Alabama district lines","Alabama gerrymandering rules","Map requirements AL"]', 'Under the Alabama Constitution and legislative guidelines, districts must be contiguous, reasonably compact, and adhere to strict population equality (one person, one vote). They must comply with the federal Voting Rights Act to ensure minority voting strength is not diluted, and should minimize the splitting of counties and precincts where possible.', 'https://ballotpedia.org/Redistricting_in_Alabama', 'Alabama Legislative Reapportionment Committee Guidelines', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('8204b4f123f991f1', 'AL', '["state"]', 'redistricting', 'Are the current Alabama State Senate maps operative for the 2026 cycle?', '["Status of Alabama Senate redistricting maps","Are there pending redistricting lawsuits in Alabama?","Alabama 2026 state legislative boundaries"]', 'Yes, but they are newly court-imposed. On August 22, 2025, a federal district court struck down Alabama''s state senate map as a violation of Section 2 of the Voting Rights Act. On November 17, 2025, the court imposed a remedial map, ordering the state to use these new boundaries for the 2026 and 2030 state legislative elections.', 'https://ballotpedia.org/Redistricting_in_Alabama_after_the_2020_census', 'Ballotpedia - Redistricting in Alabama', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('3003e93c2a596bde', 'AL', '["federal"]', 'redistricting', 'What is the status of Alabama''s congressional map for the 2026 cycle?', '["Allen v. Milligan Alabama impact","Is the AL congressional map operative for 2026?","VRA challenges to Alabama congressional districts"]', 'The congressional map is currently highly volatile. Following the 2023 Supreme Court decision in Allen v. Milligan, a federal court imposed a map with two opportunity districts for Black voters. However, following the May 2026 Supreme Court ruling in Louisiana v. Callais (which altered standards for racial gerrymandering), injunctions blocking the state''s prior map were lifted. The legislature has called special sessions to revert to maps that could eliminate the second majority-Black district, meaning the operative boundaries for the 2026 midterms are in flux.', 'https://time.com/article/2026/05/05/republicans-redistricting-supreme-court-voting-rights-act-louisiana-alabama-tennessee/', 'TIME / SCOTUS Rulings', '2026-05-17', 'volatile', 'secondary_source', 'Federal candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('17c5313c97225d6b', 'AL', '["federal","state"]', 'redistricting', 'Can the Alabama legislature easily conduct mid-decade redistricting?', '["Alabama mid-decade redistricting restrictions","Can the AL legislature redraw maps before 2030?","Federal injunctions against Alabama redistricting"]', 'Generally, mid-decade redistricting is restricted by both state constitutional principles and federal court injunctions (which previously barred Alabama from redrawing its maps until after the 2030 census). However, the recent May 2026 Supreme Court actions lifting those injunctions have opened the door for the legislature to legally conduct mid-decade redistricting if authorized by the courts.', 'https://www.ncsl.org/redistricting-and-census/changing-the-maps-tracking-mid-decade-redistricting', 'NCSL - Mid-Decade Redistricting', '2026-05-17', 'volatile', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('27eb8449f4b649ea', 'AL', '["state"]', 'recall_rules', 'Does Alabama have a recall mechanism for state officials?', '["Can the Governor of Alabama be recalled?","How to recall a state senator in AL","Statewide recall election rules Alabama"]', 'No. The State of Alabama does not have any legal or constitutional mechanism for the recall of state-level elected officials, including the Governor, statewide executives, or members of the state legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_Alabama', 'Laws governing recall in Alabama', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('1ddf9ee3a8d2df57', 'AL', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Alabama?', '["Alabama county commissioner recall rules","Signature requirement local recall Alabama","Recalling a mayor in AL"]', 'Alabama does not have a general statutory recall process for county or municipal officials. Recall is only permitted in an extremely narrow subset of municipalities if explicitly authorized by a local act passed by the state legislature, meaning the vast majority of local officials cannot be recalled.', 'https://ballotpedia.org/Laws_governing_recall_in_Alabama', 'Laws governing recall in Alabama', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('1347dfc0b175cf3e', 'AL', '["state"]', 'ballot_access', 'Does Alabama have a citizen initiative process?', '["How to get an initiative on the AL ballot","Alabama citizen initiative signature requirements","Can citizens propose laws in Alabama?"]', 'No. Alabama is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot. All statewide ballot measures must be referred by the state legislature.', 'https://ballotpedia.org/Initiative_and_referendum_in_Alabama', 'Ballotpedia - Initiative and Referendum in Alabama', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('17a1c9046ce80488', 'AL', '["state"]', 'ballot_access', 'How does the Alabama legislature refer a constitutional amendment to the voters?', '["Legislative referral process Alabama","Referendum by legislature AL","Can the AL legislature put a constitutional amendment on the ballot?"]', 'The Alabama State Legislature can propose a constitutional amendment by securing a three-fifths (60%) supermajority vote in both the House of Representatives and the State Senate. The proposed amendment is then referred directly to the voters on the next general election ballot and does not require the Governor''s signature.', 'https://ballotpedia.org/Article_XVIII,_Alabama_Constitution', 'Alabama Constitution Article XVIII', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('6b265eb187b75c04', 'AL', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Alabama?', '["Alabama ballot measure pass threshold","Does a measure need a supermajority in AL?","Majority vote requirements Alabama ballot measures"]', 'In Alabama, a legislatively referred constitutional amendment requires only a simple majority (over 50%) of the total votes cast on that specific measure to pass and become part of the state constitution.', 'https://ballotpedia.org/Article_XVIII,_Alabama_Constitution', 'Alabama Constitution Article XVIII', '2026-05-17', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('44b7f59c925ba364', 'AL', '["state"]', 'ballot_access', 'What is the threshold and deadline for a veto referendum in Alabama?', '["How to refer an AL bill to the ballot","Alabama citizen referendum rules","Veto referendum signature threshold Alabama state"]', 'Alabama does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_Alabama', 'Ballotpedia - Initiative and Referendum in Alabama', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('85eb6d749df70bec', 'AL', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Alabama?', '["Requirements to run for AL Secretary of State","Who can run for Secretary of State in AL?","Residency rules for Alabama SOS"]', 'Under Article V, Section 132 of the Alabama Constitution, a candidate for Secretary of State must be at least 25 years old, a citizen of the United States for at least seven years, and a resident of Alabama for at least five years preceding the election.', 'https://law.justia.com/constitution/alabama/CA-245669.html', 'Alabama Constitution Article V, Section 132', '2026-05-17', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('abf9fc13a3676b2e', 'AL', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Alabama?', '["Eligibility for Alabama State Treasurer","Who can run for State Treasurer in AL?","Alabama Treasurer residency requirements"]', 'Under Article V, Section 132 of the Alabama Constitution, the qualifications for State Treasurer are identical to those for the Secretary of State: a candidate must be at least 25 years old, a U.S. citizen for seven years, and a resident of Alabama for five years preceding the election.', 'https://law.justia.com/constitution/alabama/CA-245669.html', 'Alabama Constitution Article V, Section 132', '2026-05-17', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('0e9b896918e0abc3', 'AL', '["state"]', 'candidate_eligibility', 'What is the Commissioner of Agriculture and Industries in Alabama, and what are the qualifications?', '["What does the AL Agriculture Commissioner do?","Qualifications for Alabama Ag Commissioner","Is the Ag Commissioner elected in AL?"]', 'The Commissioner of Agriculture and Industries is a statewide elected executive officer. The Alabama Constitution requires the candidate to be 25 years old, a US citizen for 7 years, and a state resident for 5 years. Furthermore, Alabama Code § 2-2-2 requires the Commissioner to be ''a person of good moral character of recognized executive ability and trained in the practice and science of agriculture.''', 'https://law.justia.com/codes/alabama/title-2/chapter-2/article-1/section-2-2-2/', 'Alabama Code § 2-2-2', '2026-05-17', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('89a300b52c451a12', 'AL', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Alabama?', '["Run for school board Alabama requirements","Who can be a school board member in AL?","School board residency rules Alabama"]', 'To run for a local school board in Alabama, candidates must be of good moral character, hold a high school diploma (or equivalent), not be a convicted felon or on the Sex Offender Registry, and be a resident of the district (for county boards) or city (for city boards) they seek to represent.', 'https://www.alabamaschoolboards.org/get-on-board/item-03', 'Alabama Association of School Boards', '2026-05-17', 'static', 'secondary_source', 'School board candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('2290a0297a8a7c15', 'AL', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Alabama Supreme Court justices?', '["Alabama Supreme Court Justice eligibility","Years of practice required for AL Supreme Court","Are Alabama judges elected or appointed?"]', 'Alabama Supreme Court Justices are elected in statewide, partisan elections. A candidate must be licensed to practice law in the state of Alabama, and must reside in the state. Additionally, under Article VI, Section 155 of the Alabama Constitution, a candidate cannot be elected or appointed to a judicial office if they have reached the age of 70.', 'https://judicial.alabama.gov/', 'Alabama Judicial System', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('8395bfa8be7a4ea3', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in Alabama?', '["How to fix a rejected signature in AL","Alabama ballot cure process deadline","Missing signature on AL mail ballot"]', 'Alabama law DOES NOT currently provide a statutory cure process for absentee ballots. If a voter''s absentee ballot affidavit envelope is missing a signature, missing the required two witness signatures (or notary), or missing a copy of their photo ID, the ballot is generally rejected by the Absentee Election Manager without granting the voter a post-election window to fix the error.', 'https://www.sos.alabama.gov/alabama-votes/voter/absentee-voting', 'Alabama Secretary of State - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('f296c9377f2fb065', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Alabama?', '["When are military ballots due in Alabama?","UOCAVA return deadline AL","Overseas voting rules Alabama state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots returned by mail must be postmarked by Election Day and received by the Absentee Election Manager no later than noon on the seventh (7th) day following the election.', 'https://www.fvap.gov/guide/chapter2/alabama', 'FVAP.gov - Alabama', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('674b072d7152de63', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Alabama?', '["What is a provisional ballot in AL?","Voting without ID Alabama","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s name is not on the poll list, if they fail to present a valid photo ID, or if an inspector challenges their eligibility. The voter must complete a reidentification form. If the provisional ballot was cast due to a lack of ID, the voter has until 5:00 p.m. on the Friday following the election to bring a valid photo ID to the Board of Registrars for the ballot to count.', 'https://www.sos.alabama.gov/sites/default/files/election-2022/2023_Provisional_Ballot_Guide.pdf', 'Alabama Secretary of State - Provisional Voting Guide', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('259c57ebdba871e2', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Alabama have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Alabama DMV?","AL motor voter automatic registration","Do I have to register to vote if I get an AL driver''s license?"]', 'No. Alabama does not have Automatic Voter Registration (AVR). While the Alabama Law Enforcement Agency (ALEA) offers eligible citizens the opportunity to register to vote when applying for a license (in compliance with federal Motor Voter laws), the process is not automatic; voters must actively opt-in.', 'https://www.sos.alabama.gov/alabama-votes/voter/register-to-vote', 'Alabama Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('be34193915ea12b0', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Alabama offer Online Voter Registration?', '["Can I register to vote online in AL?","Alabama electronic voter registration","AL SOS online registration portal"]', 'Yes. Eligible Alabama residents with a valid state driver''s license or non-driver ID card can register to vote or update their registration using the Secretary of State''s online voter registration portal. The deadline is 15 days prior to an election.', 'https://www.sos.alabama.gov/alabama-votes/voter/register-to-vote', 'Alabama Secretary of State - Online Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('c9823f4e2150ca55', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Alabama maintain its voter registration lists?', '["AL voter list maintenance rules","How are inactive voters handled in Alabama?","Alabama voter roll cleaning process"]', 'The Board of Registrars continuously updates the voter list and is mandated to conduct list maintenance activities each January. This includes removing voters based on death records, felony convictions, and National Change of Address (NCOA) data. Voters who do not respond to confirmation notices and fail to vote in two consecutive federal general elections are purged.', 'https://alison.legislature.state.al.us/code-of-alabama?section=17-4-7', 'Alabama Code § 17-4-7', '2026-05-17', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('69178df3da2d74d3', 'AL', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Alabama voter file?', '["Alabama voter database access cost","How to get the voter list in AL","What data is included in the Alabama voter file?"]', 'Campaigns and political committees can purchase the statewide or county-specific voter registration lists from the Secretary of State. The data request requires a fee, and the file includes voter names, addresses, and voting history (which primaries they participated in, but not how they voted).', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('3da4652d38cab733', 'AL', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Alabama elections?', '["How are tied elections decided in Alabama?","Tie-breaker rules Alabama elections","What happens if a race is tied in AL?"]', 'In the extremely rare event of an exact tie in a general election or a primary runoff, Alabama law dictates that the winner is determined by casting lots (e.g., a coin toss or drawing names) conducted by the official canvassing authority, such as the Secretary of State or county election commission.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('5a199825d39a9860', 'AL', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Alabama?', '["Does Alabama use ranked choice voting?","RCV status in Alabama 2026","Instant runoff voting AL"]', 'No. Ranked Choice Voting (RCV) is strictly prohibited in Alabama. During the 2024 legislative session, the Alabama Legislature passed a law (SB 186) officially banning the use of Ranked Choice Voting for any local, state, or federal election in the state.', 'https://legislature.state.al.us/', 'Alabama State Legislature (SB 186)', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('e5ae2bfcd4a9fd61', 'AL', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Alabama campaign materials?', '["Alabama ''Paid for by'' rules","Campaign ad disclaimer requirements AL","Political taglines Alabama FCPA"]', 'The Alabama Fair Campaign Practices Act (FCPA) requires all political advertising (print, broadcast, and digital) to prominently display a ''Paid for by'' disclaimer. The disclaimer must clearly identify the person, candidate committee, or PAC that financed the communication.', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('e545a3722173acfd', 'AL', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Alabama?', '["AL campaign coordination rules","When is a PAC expenditure not independent in Alabama?","Prohibition on candidate-PAC coordination AL"]', 'An independent expenditure becomes ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. While coordinated expenditures are legal due to the lack of contribution limits in Alabama, they are classified as in-kind contributions and must be fully disclosed by the campaign.', 'https://fcpa.alabamavotes.gov/', 'Alabama FCPA Guidelines', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('069fbfaaea208bca', 'AL', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Alabama?', '["AL FCPA late fee","Penalty for missing an Alabama campaign finance deadline","Ethics Commission fine for late filing AL"]', 'The Alabama Ethics Commission levies significant fines for late FCPA reports. Fines are calculated based on the number of days late or the amount of undisclosed funds. Standard penalties are $300 or 10% of the amount not properly reported, whichever is greater, and can escalate for repeated offenses.', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('36bb2ffa1c602373', 'AL', '["state","county","municipal"]', 'finance_ethics', 'When and how must an Alabama campaign committee terminate?', '["Closing an Alabama campaign committee","FCPA committee termination requirements","Final campaign finance report Alabama"]', 'A candidate committee may formally terminate its registration when it will no longer receive contributions or make expenditures. The committee must legally disburse all surplus funds, achieve a zero cash balance, resolve all debts, and file a formal Termination Report through the FCPA portal.', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('6bd1aa08b282f318', 'AL', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Alabama?', '["AL independent expenditure reporting FCPA","Disclosure for AL independent expenditure groups","Reporting thresholds for outside spending Alabama"]', 'Entities making independent expenditures must file reports disclosing their spending to the Secretary of State''s FCPA system. Due to the lack of contribution limits, the focus in Alabama is heavily on ensuring complete transparency of where outside funds are originating and how they are spent.', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('6683d55149197eb3', 'AL', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Alabama?', '["Alabama in-kind contribution valuation rules","Reporting non-monetary donations Alabama campaign","Fair market value for in-kind gifts AL"]', 'In-kind contributions (donated goods, services, or discounts not available to the general public) must be reported at their fair market value on FCPA disclosures. They are documented simultaneously as both a contribution receipt and an operating expenditure.', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('2ab85ea100addfc0', 'AL', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Alabama?', '["Alabama candidate personal loan limits","Can I pay myself back for a campaign loan in AL?","Reporting candidate loans in FCPA"]', 'A candidate may loan an unlimited amount of their own personal funds to their campaign committee. The loan must be properly reported on FCPA disclosures. Candidates are legally permitted to repay these personal loans from campaign contributions raised during the cycle.', 'https://fcpa.alabamavotes.gov/', 'Alabama Secretary of State - FCPA', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('9165d737dbc97fa9', 'AL', '["state","county","municipal"]', 'finance_ethics', 'What can Alabama candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in AL?","AL surplus campaign funds rules","Donating remaining campaign funds Alabama"]', 'Unexpended campaign funds cannot be converted to personal use. Under the FCPA, candidates may retain surplus funds for a future campaign, return them to contributors, donate them to an IRS-recognized charity, or transfer them to another candidate, PAC, or political party (since transfers are unlimited).', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('ef9771d99c8bdc9e', 'AL', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Alabama?', '["AL PAC donation limits to candidates 2026","Political committee vs individual contribution limit Alabama","Maximum PAC gift to state legislator AL"]', 'In Alabama, Political Action Committees (PACs) are subject to the same contribution rules as individuals—meaning there are NO limits. A PAC is permitted to contribute completely unlimited amounts of money to a candidate for state or legislative office.', 'https://ethics.alabama.gov/', 'Alabama Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'State and County candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('fa5ead3b37b29d27', 'AL', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Alabama?', '["When are county sheriffs elected in AL?","Alabama county official term lengths","Are county commissions on the 2026 ballot?"]', 'Elected county officials in Alabama—including Sheriffs, Probate Judges, Circuit Clerks, and County Commissioners—generally serve four-year or six-year terms depending on the specific office. Most county executive offices are heavily featured on the 2026 midterm ballot, aligning with the Governor''s cycle.', 'https://www.sos.alabama.gov/', 'Alabama Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('a390ae5f42e7e3ec', 'AL', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Alabama elections?', '["When are Alabama election results official?","AL certification deadline","State Canvassing Board meeting Alabama"]', 'County canvassing boards meet at noon on the Tuesday following the election (7 days later) to officially canvass provisional and UOCAVA ballots and certify local results. The State Canvassing Board (composed of the Governor, Secretary of State, and Attorney General) must meet to certify statewide and federal results no later than 22 days after the election.', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State - Canvass', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T17-08-11_alabama_full_v1'),
  ('8822c00512293981', 'AL', '["federal","state"]', 'election_dates', 'When and how are special elections called in Alabama?', '["Alabama special election timeline","Who calls a special election to fill a US House vacancy in AL?","Filling a midterm vacancy Alabama"]', 'Special elections to fill federal or state legislative vacancies are called by a proclamation from the Governor. The Governor holds significant discretion in setting the exact dates for the special primary, runoff, and general election, ensuring there is sufficient time (at least 70-80 days) for qualifying, ballot printing, and UOCAVA compliance.', 'https://www.sos.alabama.gov/alabama-votes/voter/election-information', 'Alabama Secretary of State - Special Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T17-08-11_alabama_full_v1')
